import{_ as s,W as o,X as e,Y as n,Z as t,a0 as r}from"./framework-91490e6a.js";const a="/assets/images/ChinaJoy2023.jpg",c={},_=t("p",null,"我是一个自闭的社恐人。",-1),i=t("figure",null,[t("img",{src:a,alt:"✝️昇天✝️",tabindex:"0",loading:"lazy"}),t("figcaption",null,"✝️昇天✝️")],-1),p=r("<p>早在初中就听闻中国只有一个城市——上海。待我成为了上海的社畜便发现果真如此。</p><p>光是来的第一个月就有三场漫展：<strong>CCG</strong>、<strong>BW</strong>、<strong>CJ</strong>。由于CCG那一周我只有一个人，我当然没有敢去。但是BW和CJ的那两周各有友人来我家借宿，于是便得以同游。</p><p>在盛大性上，BW是要胜于CJ的，在BW我也看到很多想集邮的coser，但是并没有敢。于是之后陷入了深深的后悔之中——我为什么没有去问呢？问了如果同意，那皆大欢喜；<strong>如果被拒绝，那也顶多后悔一时，不会像现在这样后悔一世啊。最起码总要去尝试一下吧！</strong></p><p>于是在回去之后，我进行了反思。<strong>光鲜亮丽的背后都是由脚踏实地的努力构成的。</strong> 像BW这样的展会，每一个参展的展商、每一个coser都是付出了努力来表现自己的，他们在服化道上付出成本与心血，目标是什么呢？<strong>承认欲求</strong>（商业coser有可能是其他目标，我这里仅指业余爱好者）。付出努力将自己打扮成另一个自己想成为的自己，那当然是想要得到其他人的承认的——「啊，我认出来了，你是那个……」「好漂亮好还原啊」……而集邮，虽然是一种低成本的小行为，但是其实是一种两全其美的事情的，集邮方获得了珍贵的回忆，而被集邮方也满足了承认欲求。</p><p>于是在一周后的CJ，我终于迈出了第一步。现在想来当时BW的同游者想集邮而没敢说出口，如果我能再回到那个时间的话，我会去代替他说的：“你好，我有个朋友想和你集邮，可以吗？”这也是适用于社恐双人成行的やりかた。</p>",5);function g(l,d){return o(),e("div",null,[_,i,n(" more "),p])}const C=s(c,[["render",g],["__file","First_Step.html.vue"]]);export{C as default};
